function extractAssets(urls) {
  const result = {
    elementor: [],
    fonts: []
  };

  urls.forEach(url => {
    if (url.includes('elementor')) {
      result.elementor.push(url);
    }

    if (url.includes('fonts.googleapis.com')) {
      result.fonts.push(url);
    }
  });

  return result;
}

// Example usage:
const urls = $input.first().json.style

const extracted = extractAssets(urls);
return {style: extracted}

let css = '';
for (const item of $input.first().json.data) {
   css += item.css;
}

return {css:css}

